using ContosoUniversity.Models;

namespace ContosoUniversity.Tests;

public class PaginatedListTests
{
    [Fact]
    public void Constructor_WithItems_SetsProperties()
    {
        // Arrange
        var items = new List<string> { "a", "b", "c" };

        // Act
        var result = new PaginatedList<string>(items, 10, 2, 3);

        // Assert
        Assert.Equal(2, result.PageIndex);
        Assert.Equal(4, result.TotalPages); // ceil(10/3) = 4
        Assert.Equal(3, result.Count);
        Assert.Contains("a", result);
        Assert.Contains("b", result);
        Assert.Contains("c", result);
    }

    [Theory]
    [InlineData(10, 3, 4)]   // ceil(10/3) = 4
    [InlineData(10, 5, 2)]   // ceil(10/5) = 2
    [InlineData(1, 10, 1)]   // ceil(1/10) = 1
    [InlineData(0, 5, 0)]    // ceil(0/5) = 0
    [InlineData(11, 5, 3)]   // ceil(11/5) = 3
    public void Constructor_VariousCounts_CalculatesTotalPagesCorrectly(int count, int pageSize, int expectedTotalPages)
    {
        // Act
        var result = new PaginatedList<int>(new List<int>(), count, 1, pageSize);

        // Assert
        Assert.Equal(expectedTotalPages, result.TotalPages);
    }

    [Theory]
    [InlineData(1, false)]   // first page, no previous
    [InlineData(2, true)]    // second page, has previous
    [InlineData(3, true)]    // third page, has previous
    public void HasPreviousPage_VariousPageIndexes_ReturnsExpected(int pageIndex, bool expected)
    {
        // Act
        var result = new PaginatedList<int>(new List<int>(), 30, pageIndex, 10);

        // Assert
        Assert.Equal(expected, result.HasPreviousPage);
    }

    [Theory]
    [InlineData(1, 3, true)]  // page 1 of 3, has next
    [InlineData(3, 3, false)] // page 3 of 3, no next
    [InlineData(2, 3, true)]  // page 2 of 3, has next
    public void HasNextPage_VariousPageIndexes_ReturnsExpected(int pageIndex, int totalPages, bool expected)
    {
        // Arrange - count = totalPages * pageSize
        var count = totalPages * 10;

        // Act
        var result = new PaginatedList<int>(new List<int>(), count, pageIndex, 10);

        // Assert
        Assert.Equal(expected, result.HasNextPage);
    }

    [Fact]
    public void Create_FromQueryable_ReturnsPaginatedItems()
    {
        // Arrange
        var source = Enumerable.Range(1, 20).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 2, 5);

        // Assert
        Assert.Equal(2, result.PageIndex);
        Assert.Equal(4, result.TotalPages);
        Assert.Equal(5, result.Count);
        Assert.Equal(new[] { 6, 7, 8, 9, 10 }, result);
    }

    [Fact]
    public void Create_FirstPage_ReturnsFirstItems()
    {
        // Arrange
        var source = Enumerable.Range(1, 15).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 1, 5);

        // Assert
        Assert.Equal(1, result.PageIndex);
        Assert.Equal(3, result.TotalPages);
        Assert.Equal(new[] { 1, 2, 3, 4, 5 }, result);
    }

    [Fact]
    public void Create_LastPagePartial_ReturnsRemainingItems()
    {
        // Arrange
        var source = Enumerable.Range(1, 7).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 2, 5);

        // Assert
        Assert.Equal(2, result.PageIndex);
        Assert.Equal(2, result.TotalPages);
        Assert.Equal(new[] { 6, 7 }, result);
    }

    [Fact]
    public void Create_EmptySource_ReturnsEmptyList()
    {
        // Arrange
        var source = Enumerable.Empty<int>().AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 1, 10);

        // Assert
        Assert.Empty(result);
        Assert.Equal(0, result.TotalPages);
    }
}

using ContosoUniversity.Models;
using ContosoUniversity.Services;

namespace ContosoUniversity.Tests;

public class NotificationServiceTests : IDisposable
{
    private readonly NotificationService _sut;

    public NotificationServiceTests()
    {
        _sut = new NotificationService();
        // Drain any leftover notifications from static queue
        while (_sut.ReceiveNotification() != null) { }
    }

    public void Dispose()
    {
        _sut.Dispose();
    }

    [Fact]
    public void SendNotification_ValidData_EnqueuesNotification()
    {
        // Act
        _sut.SendNotification("Student", "1", EntityOperation.CREATE, "admin");

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.NotNull(notification);
        Assert.Equal("Student", notification.EntityType);
        Assert.Equal("1", notification.EntityId);
        Assert.Equal("CREATE", notification.Operation);
        Assert.Equal("admin", notification.CreatedBy);
        Assert.False(notification.IsRead);
    }

    [Fact]
    public void SendNotification_WithDisplayName_GeneratesCorrectMessage()
    {
        // Act
        _sut.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE, "admin");

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.NotNull(notification);
        Assert.Equal("New Student 'John Doe' has been created", notification.Message);
    }

    [Fact]
    public void SendNotification_WithoutDisplayName_GeneratesIdBasedMessage()
    {
        // Act
        _sut.SendNotification("Student", "42", EntityOperation.CREATE);

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.NotNull(notification);
        Assert.Equal("New Student (ID: 42) has been created", notification.Message);
    }

    [Theory]
    [InlineData(EntityOperation.CREATE, "New Course 'Math' has been created")]
    [InlineData(EntityOperation.UPDATE, "Course 'Math' has been updated")]
    [InlineData(EntityOperation.DELETE, "Course 'Math' has been deleted")]
    public void SendNotification_DifferentOperations_GeneratesCorrectMessage(EntityOperation operation, string expectedMessage)
    {
        // Act
        _sut.SendNotification("Course", "1", "Math", operation, "admin");

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.NotNull(notification);
        Assert.Equal(expectedMessage, notification.Message);
    }

    [Fact]
    public void SendNotification_NoUserName_DefaultsToSystem()
    {
        // Act
        _sut.SendNotification("Student", "1", EntityOperation.CREATE);

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.NotNull(notification);
        Assert.Equal("System", notification.CreatedBy);
    }

    [Fact]
    public void ReceiveNotification_EmptyQueue_ReturnsNull()
    {
        // Act
        var notification = _sut.ReceiveNotification();

        // Assert
        Assert.Null(notification);
    }

    [Fact]
    public void ReceiveNotification_MultipleNotifications_ReturnsFIFO()
    {
        // Arrange
        _sut.SendNotification("Student", "1", "First", EntityOperation.CREATE);
        _sut.SendNotification("Course", "2", "Second", EntityOperation.UPDATE);

        // Act & Assert
        var first = _sut.ReceiveNotification();
        Assert.Equal("Student", first!.EntityType);
        Assert.Equal("New Student 'First' has been created", first.Message);

        var second = _sut.ReceiveNotification();
        Assert.Equal("Course", second!.EntityType);
        Assert.Equal("Course 'Second' has been updated", second.Message);

        Assert.Null(_sut.ReceiveNotification());
    }

    [Fact]
    public void SendNotification_SetsCreatedAt()
    {
        // Arrange
        var before = DateTime.Now;

        // Act
        _sut.SendNotification("Student", "1", EntityOperation.CREATE);

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.NotNull(notification);
        Assert.True(notification.CreatedAt >= before);
        Assert.True(notification.CreatedAt <= DateTime.Now);
    }

    [Fact]
    public void SendNotification_OverloadWithoutDisplayName_CallsFullOverload()
    {
        // Act
        _sut.SendNotification("Department", "5", EntityOperation.DELETE);

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.NotNull(notification);
        Assert.Equal("Department (ID: 5) has been deleted", notification.Message);
    }

    [Fact]
    public void MarkAsRead_DoesNotThrow()
    {
        // Act & Assert - MarkAsRead is a no-op, should not throw
        var exception = Record.Exception(() => _sut.MarkAsRead(1));
        Assert.Null(exception);
    }

    [Fact]
    public void SendNotification_WhitespaceDisplayName_UsesIdFormat()
    {
        // Act
        _sut.SendNotification("Student", "1", "   ", EntityOperation.CREATE);

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.NotNull(notification);
        Assert.Equal("New Student (ID: 1) has been created", notification.Message);
    }

    [Fact]
    public void SendNotification_EmptyDisplayName_UsesIdFormat()
    {
        // Act
        _sut.SendNotification("Student", "1", "", EntityOperation.CREATE);

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.NotNull(notification);
        Assert.Equal("New Student (ID: 1) has been created", notification.Message);
    }

    [Fact]
    public void Dispose_CanBeCalledMultipleTimes()
    {
        // Act & Assert - should not throw
        _sut.Dispose();
        var exception = Record.Exception(() => _sut.Dispose());
        Assert.Null(exception);
    }
}

