+// Minimal session state implementation for TempData
+internal class SessionStateTempDataProvider : ITempDataProvider
+{
+    private readonly SessionStateSessionStore _store;
+    public SessionStateTempDataProvider(SessionStateSessionStore store) => _store = store;
+    public IDictionary<string, object?> LoadTempData(HttpContext context) => _store.Data;
+    public void SaveTempData(HttpContext context, IDictionary<string, object?> values) => _store.Data = values;
+}
+
+internal class SessionStateSessionStore
+{
+    public IDictionary<string, object?> Data { get; set; } = new Dictionary<string, object?>();
