+
+    [Fact]
+    public void SchoolContext_CanAddAndRetrieveStudent()
+    {
+        // Arrange
+        var student = new Student
+        {
+            FirstMidName = "Test",
+            LastName = "Student",
+            EnrollmentDate = new DateTime(2023, 9, 1)
+        };
+
+        // Act
+        _context.Students.Add(student);
+        _context.SaveChanges();
+
+        // Assert
+        var retrieved = _context.Students.Find(student.ID);
+        Assert.NotNull(retrieved);
+        Assert.Equal("Test", retrieved!.FirstMidName);
+        Assert.Equal("Student", retrieved.LastName);
+    }
+
+    [Fact]
+    public void SchoolContext_CanAddAndRetrieveCourse()
+    {
+        // Arrange
+        var dept = new Department { Name = "Test", Budget = 100m, StartDate = DateTime.Today };
+        _context.Departments.Add(dept);
+        _context.SaveChanges();
+
+        var course = new Course { CourseID = 9999, Title = "Test Course", Credits = 3, DepartmentID = dept.DepartmentID };
