+
+        var dept = new Department { Name = "Test", Budget = 100m, StartDate = DateTime.Today };
+        _context.Departments.Add(dept);
+        _context.SaveChanges();
+
+        var course = new Course { CourseID = 9998, Title = "Test", Credits = 3, DepartmentID = dept.DepartmentID };
+        _context.Courses.Add(course);
+        _context.SaveChanges();
+
+        var ca = new CourseAssignment { CourseID = course.CourseID, InstructorID = instructor.ID };
+
+        // Act
+        _context.CourseAssignments.Add(ca);
+        _context.SaveChanges();
+
+        // Assert
+        var retrieved = _context.CourseAssignments.Find(course.CourseID, instructor.ID);
+        Assert.NotNull(retrieved);
+    }
+
+    [Fact]
+    public void SchoolContext_CanAddEnrollment()
+    {
+        // Arrange
+        var student = new Student
+        {
+            FirstMidName = "Test",
+            LastName = "Student",
+            EnrollmentDate = DateTime.Today
+        };
+        _context.Students.Add(student);
+        _context.SaveChanges();
+
+        var dept = new Department { Name = "Test", Budget = 100m, StartDate = DateTime.Today };
+        _context.Departments.Add(dept);
+        _context.SaveChanges();
+
+        var course = new Course { CourseID = 9997, Title = "Test", Credits = 3, DepartmentID = dept.DepartmentID };
+        _context.Courses.Add(course);
+        _context.SaveChanges();
+
+        var enrollment = new Enrollment
+        {
+            StudentID = student.ID,
+            CourseID = course.CourseID,
+            Grade = Grade.A
+        };
+
+        // Act
+        _context.Enrollments.Add(enrollment);
+        _context.SaveChanges();
+
+        // Assert
+        var retrieved = _context.Enrollments.Find(enrollment.EnrollmentID);
+        Assert.NotNull(retrieved);
+        Assert.Equal(Grade.A, retrieved!.Grade);
+    }
+}
