+using ContosoUniversity.Data;
+using ContosoUniversity.Models;
+using ContosoUniversity.Tests.Helpers;
+
+namespace ContosoUniversity.Tests;
+
+public class DbInitializerTests : IDisposable
+{
+    private readonly SchoolContext _context;
+
+    public DbInitializerTests()
+    {
+        _context = TestDbContextFactory.Create();
+    }
+
+    public void Dispose()
+    {
+        _context.Dispose();
+    }
+
+    [Fact]
+    public void Initialize_EmptyDatabase_SeedsStudents()
+    {
+        // Act
+        DbInitializer.Initialize(_context);
+
+        // Assert
+        Assert.Equal(8, _context.Students.Count());
+    }
+
+    [Fact]
+    public void Initialize_EmptyDatabase_SeedsInstructors()
+    {
+        // Act
+        DbInitializer.Initialize(_context);
+
+        // Assert
+        Assert.Equal(5, _context.Instructors.Count());
+    }
+
+    [Fact]
+    public void Initialize_EmptyDatabase_SeedsDepartments()
+    {
+        // Act
+        DbInitializer.Initialize(_context);
+
+        // Assert
+        Assert.Equal(4, _context.Departments.Count());
+    }
+
+    [Fact]
+    public void Initialize_EmptyDatabase_SeedsCourses()
+    {
+        // Act
+        DbInitializer.Initialize(_context);
+
+        // Assert
+        Assert.Equal(7, _context.Courses.Count());
+    }
+
+    [Fact]
+    public void Initialize_EmptyDatabase_SeedsEnrollments()
+    {
+        // Act
+        DbInitializer.Initialize(_context);
+
+        // Assert
+        Assert.True(_context.Enrollments.Count() > 0);
+        Assert.Equal(11, _context.Enrollments.Count());
+    }
+
+    [Fact]
+    public void Initialize_EmptyDatabase_SeedsOfficeAssignments()
+    {
+        // Act
+        DbInitializer.Initialize(_context);
+
+        // Assert
+        Assert.Equal(3, _context.OfficeAssignments.Count());
+    }
+
+    [Fact]
+    public void Initialize_EmptyDatabase_SeedsCourseAssignments()
+    {
+        // Act
+        DbInitializer.Initialize(_context);
+
+        // Assert
+        Assert.Equal(8, _context.CourseAssignments.Count());
+    }
+
+    [Fact]
+    public void Initialize_AlreadySeeded_DoesNotDuplicate()
+    {
+        // Arrange - seed once
+        DbInitializer.Initialize(_context);
+        var initialStudentCount = _context.Students.Count();
+
+        // Act - seed again
+        DbInitializer.Initialize(_context);
+
+        // Assert - counts should be same
+        Assert.Equal(initialStudentCount, _context.Students.Count());
+    }
+
+    [Fact]
+    public void Initialize_SeedsCorrectStudentNames()
+    {
+        // Act
+        DbInitializer.Initialize(_context);
+
+        // Assert
+        Assert.Contains(_context.Students, s => s.LastName == "Alexander" && s.FirstMidName == "Carson");
+        Assert.Contains(_context.Students, s => s.LastName == "Alonso" && s.FirstMidName == "Meredith");
+        Assert.Contains(_context.Students, s => s.LastName == "Olivetto" && s.FirstMidName == "Nino");
+    }
+
+    [Fact]
+    public void Initialize_SeedsCorrectDepartmentNames()
+    {
+        // Act
+        DbInitializer.Initialize(_context);
+
+        // Assert
+        var departmentNames = _context.Departments.Select(d => d.Name).ToList();
+        Assert.Contains("English", departmentNames);
+        Assert.Contains("Mathematics", departmentNames);
+        Assert.Contains("Engineering", departmentNames);
+        Assert.Contains("Economics", departmentNames);
+    }
+
+    [Fact]
+    public void Initialize_SeedsCorrectCourseTitles()
+    {
+        // Act
+        DbInitializer.Initialize(_context);
+
+        // Assert
+        var courseTitles = _context.Courses.Select(c => c.Title).ToList();
+        Assert.Contains("Chemistry", courseTitles);
+        Assert.Contains("Calculus", courseTitles);
+        Assert.Contains("Literature", courseTitles);
+    }
+}
+

